sql:
SELECT COUNT(process_id) AS process_count
FROM processes
WHERE plant_id = 1;

SELECT value, datetime
FROM process_data
WHERE datetime > '2023-01-01 00:00:00';

SELECT process_id, COUNT(*) AS data_count
FROM process_data
GROUP BY process_id;

SELECT AVG(value) AS average_value, MAX(datetime) AS latest_recording_time
FROM process_data
WHERE datetime >= '2023-01-01 00:00:00' AND datetime <= '2023-01-31 23:59:59';

